            print(f'FAIL: {url} should have raised InvalidURL')
        else:
            print(f'OK: {url} did not raise InvalidURL')
    except InvalidURL:
        if should_fail:
            print(f'OK: {url} raised InvalidURL as expected')
        else:
            print(f'FAIL: {url} should not have raised InvalidURL')
    except Exception as e:
        if should_fail:
            print(f'OK: {url} raised {type(e).__name__} (expected InvalidURL, but connection error is also fine)')
